#include <stdio.h>
#include <ctype.h>

int main() {
    char line[1000];
    fgets(line, sizeof(line), stdin);

    int digit_count = 0, space_count = 0, other_count = 0;

    for (int i = 0; line[i] != '\0'; i++) {
        if (line[i] == '\n') continue;
        if (isdigit(line[i])) {
            digit_count++;
        } else if (line[i] == ' ') {
            space_count++;
        } else {
            other_count++;
        }
    }

    printf("%d\n%d\n%d\n", digit_count, space_count, other_count);
    return 0;
}


