#include <stdio.h>

int main() {
    int n, original = n;
    scanf("%d", &n);
    original = n;

    int reversed = 0;
    int temp = n;

    while (temp > 0) {
        int digit = temp % 10;
        reversed = reversed * 10 + digit;
        temp /= 10;
    }

    printf("Reversed: %d\n", reversed);

    if (original == reversed) {
        printf("Palindrome: yes\n");
    } else {
        printf("Palindrome: no\n");
    }

    return 0;
}


